backend-service-ecr.terraform_block:
resource "aws_ecr_lifecycle_policy" "backend_service_lifecycle" {
  repository = aws_ecr_repository.backend_service.name

  policy = jsonencode({
    rules = [
      {
        rulePriority = 1,
        description  = "Expire untagged images after 1 day",
        selection    = {
          tagStatus   = "UNTAGGED",
          countType   = "SINCE_IMAGE_PUSHED",
          countUnit   = "DAYS",
          countNumber = 1
        },
        action = {
          type = "EXPIRE"
        }
      },
      {
        rulePriority = 2,
        description  = "Keep only the 30 most recent tagged images",
        selection    = {
          tagStatus   = "TAGGED",
          countType   = "IMAGE_COUNT_MORE_THAN",
          countNumber = 30
        },
        action = {
          type = "EXPIRE"
        }
      }
    ]
  })

  tags = {
    Name           = "backend-service-lifecycle"
    Environment    = "production"
    FinOpsAction   = "SET_LIFECYCLE"
    FinOpsReviewed = "true"
  }
}

